  1→/**
  2→ * S3/MinIO Storage Client
  3→ *
  4→ * Provides file upload, deletion, and presigned URL generation for MinIO/S3.
  5→ * Configured via environment variables:
  6→ * - S3_ENDPOINT: MinIO/S3 endpoint URL
  7→ * - S3_ACCESS_KEY: Access key ID
  8→ * - S3_SECRET_KEY: Secret access key
  9→ * - S3_BUCKET: Bucket name
 10→ * - S3_FORCE_PATH_STYLE: Set "true" for MinIO
 11→ */
 12→
 13→import { S3Client, PutObjectCommand, DeleteObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
 14→import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
 15→
 16→// S3 client singleton
 17→let s3Client: S3Client | null = null;
 18→
 19→/**
 20→ * Get or create the S3 client instance
 21→ */
 22→function getS3Client(): S3Client {
 23→  if (!s3Client) {
 24→    const endpoint = process.env.S3_ENDPOINT;
 25→    const accessKeyId = process.env.S3_ACCESS_KEY;
 26→    const secretAccessKey = process.env.S3_SECRET_KEY;
 27→    const bucket = process.env.S3_BUCKET;
 28→    const forcePathStyle = process.env.S3_FORCE_PATH_STYLE === 'true';
 29→
 30→    if (!endpoint || !accessKeyId || !secretAccessKey || !bucket) {
 31→      throw new Error(
 32→        'Missing S3 configuration. Ensure S3_ENDPOINT, S3_ACCESS_KEY, S3_SECRET_KEY, and S3_BUCKET are set.'
 33→      );
 34→    }
 35→
 36→    s3Client = new S3Client({
 37→      endpoint,
 38→      region: process.env.S3_REGION || 'us-east-1',
 39→      credentials: {
 40→        accessKeyId,
 41→        secretAccessKey,
 42→      },
 43→      forcePathStyle,
 44→    });
 45→  }
 46→  return s3Client;
 47→}
 48→
 49→/**
 50→ * Get the configured bucket name
 51→ */
 52→function getBucket(): string {
 53→  const bucket = process.env.S3_BUCKET;
 54→  if (!bucket) {
 55→    throw new Error('S3_BUCKET environment variable is not set');
 56→  }
 57→  return bucket;
 58→}
 59→
 60→/**
 61→ * Upload a file to S3/MinIO
 62→ *
 63→ * @param key - Storage key (path within bucket)
 64→ * @param stream - File content as Buffer or Uint8Array
 65→ * @param mimeType - Content type (e.g., 'application/pdf', 'image/jpeg')
 66→ * @returns The storage key
 67→ */
 68→export async function uploadFile(
 69→  key: string,
 70→  stream: Buffer | Uint8Array,
 71→  mimeType: string
 72→): Promise<string> {
 73→  const client = getS3Client();
 74→  const bucket = getBucket();
 75→
 76→  try {
 77→    const command = new PutObjectCommand({
 78→      Bucket: bucket,
 79→      Key: key,
 80→      Body: stream,
 81→      ContentType: mimeType,
 82→    });
 83→
 84→    await client.send(command);
 85→    return key;
 86→  } catch (error) {
 87→    console.error('S3 upload failed:', { key, error: error instanceof Error ? error.message : String(error) });
 88→    throw new Error(`Failed to upload file to S3: ${error instanceof Error ? error.message : String(error)}`);
 89→  }
 90→}
 91→
 92→/**
 93→ * Delete a file from S3/MinIO
 94→ *
 95→ * @param key - Storage key of the file to delete
 96→ */
 97→export async function deleteFile(key: string): Promise<void> {
 98→  const client = getS3Client();
 99→  const bucket = getBucket();
100→
101→  try {
102→    const command = new DeleteObjectCommand({
103→      Bucket: bucket,
104→      Key: key,
105→    });
106→
107→    await client.send(command);
108→  } catch (error) {
109→    console.error('S3 deletion failed:', { key, error: error instanceof Error ? error.message : String(error) });
110→    throw new Error(`Failed to delete file from S3: ${error instanceof Error ? error.message : String(error)}`);
111→  }
112→}
113→
114→/**
115→ * Generate a presigned URL for temporary access
116→ *
117→ * @param key - Storage key
118→ * @param expiresIn - URL expiration time in seconds (default: 3600 = 1 hour)
119→ * @returns Presigned URL string
120→ */
121→export async function getPresignedUrl(key: string, expiresIn: number = 3600): Promise<string> {
122→  const client = getS3Client();
123→  const bucket = getBucket();
124→
125→  try {
126→    const command = new GetObjectCommand({
127→      Bucket: bucket,
128→      Key: key,
129→    });
130→
131→    return await getSignedUrl(client, command, { expiresIn });
132→  } catch (error) {
133→    console.error('Failed to generate presigned URL:', { key, error: error instanceof Error ? error.message : String(error) });
134→    throw new Error(`Failed to generate presigned URL: ${error instanceof Error ? error.message : String(error)}`);
135→  }
136→}
137→
138→/**
139→ * Generate a unique storage key for uploads
140→ *
141→ * @param fileName - Original file name
142→ * @param entityType - Entity type (e.g., 'deal', 'project')
143→ * @param entityId - Entity ID
144→ * @returns Storage key in format: {entityType}/{entityId}/{timestamp}-{sanitized-filename}
145→ */
146→export function generateStorageKey(fileName: string, entityType: string, entityId: string): string {
147→  const timestamp = Date.now();
148→  // Sanitize filename: remove special chars, replace spaces with dashes
149→  const sanitized = fileName
150→    .toLowerCase()
151→    .replace(/[^a-z0-9.\s-]/g, '') // Remove special chars
152→    .replace(/\s+/g, '-') // Replace spaces with dashes
153→    .replace(/-+/g, '-') // Collapse multiple dashes
154→    || 'file';
155→
156→  return `${entityType}/${entityId}/${timestamp}-${sanitized}`;
157→}
